#include <unistd.h>

// Si1133 I2C Address
#define SI1133_I2C_ADDR 0x60

// Si1133 Register Addresses
#define SI1133_REG_PART_ID 0x00
#define SI1133_REG_REV_ID 0x01
#define SI1133_REG_SEQ_ID 0x02
#define SI1133_REG_INT_CFG 0x03
#define SI1133_REG_IRQ_ENABLE 0x04
#define SI1133_REG_HW_KEY 0x07
#define SI1133_REG_MEASURE_RATE 0x08
#define SI1133_REG_ALS_VIS_DATA0 0x22
#define SI1133_REG_ALS_VIS_DATA1 0x23
#define SI1133_REG_ALS_IR_DATA0 0x24
#define SI1133_REG_ALS_IR_DATA1 0x25
#define SI1133_REG_UV_INDEX_DATA0 0x2C
#define SI1133_REG_UV_INDEX_DATA1 0x2D
#define SI1133_REG_UV_INDEX_DATA2 0x2E

// Global Variables
int i2c_fd;

// Function to initialize the Si1133 sensor
int si1133_init() {
    // Check for valid I2C connection
    if (i2c_fd == -1) {
        fprintf(stderr, "Error: I2C device not initialized.\n");
        return -1;
    }

    // Reset the sensor (sequence ID reset)
    if (wiringPiI2CWriteReg8(i2c_fd, SI1133_REG_SEQ_ID, 0x01) < 0) {
        fprintf(stderr, "Error: Failed to reset Si1133 sensor: %s\n", strerror(errno));
        return -1;
    }
    usleep(10000); // Wait for reset to complete

    // Enable UV index measurement
    if (wiringPiI2CWriteReg8(i2c_fd, SI1133_REG_MEASURE_RATE, 0x04) < 0) {
        fprintf(stderr, "Error: Failed to enable UV index measurement: %s\n", strerror(errno));
        return -1;
    }

    return 0;
}

// Function to read UV index, ambient light, and IR data from the sensor
int si1133_read_data(int *uv_index, int *ambient_light, int *ir_data) {
    int vis_data0, vis_data1, ir_data0, ir_data1;
    int uv_data0, uv_data1, uv_data2;

    // Read ambient light and IR data
    vis_data0 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_VIS_DATA0);
    vis_data1 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_VIS_DATA1);
    ir_data0 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_IR_DATA0);
    ir_data1 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_IR_DATA1);

    if (vis_data0 < 0 || vis_data1 < 0 || ir_data0 < 0 || ir_data1 < 0) {
        fprintf(stderr, "Error: Failed to read ambient light and IR data: %s\n", strerror(errno));
        return -1;
    }

    *ambient_light = (vis_data1 << 8) | vis_data0;
    *ir_data = (ir_data1 << 8) | ir_data0;

    // Read UV index data
    uv_data0 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_UV_INDEX_DATA0);
    uv_data1 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_UV_INDEX_DATA1);
    uv_data2 = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_UV_INDEX_DATA2);

    if (uv_data0 < 0 || uv_data1 < 0 || uv_data2 < 0) {
        fprintf(stderr, "Error: Failed to read UV index data: %s\n", strerror(errno));
        return -1;
    }

    *uv_index = (uv_data2 << 16) | (uv_data1 << 8) | uv_data0;

    return 0;
}

// Function to log data to a file
int log_data(int uv_index, int ambient_light, int ir_data) {
    FILE *fp = fopen("light_data.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open log file: %s\n", strerror(errno));
        return -1;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s, UV Index: %d, Ambient Light: %d, IR Data: %d\n", timestamp, uv_index, ambient_light, ir_data);
    fclose(fp);

    return 0;
}

int main() {
    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(SI1133_I2C_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "Error: Failed to initialize I2C: %s\n", strerror(errno));
        return 1;
    }

    // Initialize Si1133 sensor
    if (si1133_init() != 0) {
        fprintf(stderr, "Error: Failed to initialize Si1133 sensor.\n");
        return 1;
    }

    // Main loop
    while (1) {
        int uv_index, ambient_light, ir_data;

        // Read sensor data
        if (si1133_read_data(&uv_index, &ambient_light, &ir_data) == 0) {
            // Log data to file
            if (log_data(uv_index, ambient_light, ir_data) != 0) {
                fprintf(stderr, "Error: Failed to log data.\n");
            }
        } else {
            fprintf(stderr, "Error: Failed to read sensor data.\n");
        }

        usleep(100000); // Delay for 100ms
    }

    return 0;
}

