float read_temperature(int i2c_fd) {
    int raw_temp = wiringPiI2CReadReg8(i2c_fd, 0x00); // Read temperature register
    if (raw_temp == -1) {
        fprintf(stderr, "Error reading temperature from LM75B!\n");
        return 0.0; // Return 0.0 on error
    }

    // Convert raw temperature to Celsius
    float temperature = (float)raw_temp * 0.125;

    return temperature;
