#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <softPwm.h>

#define MAX31855_SPI_CHANNEL 0
#define GPIO_PWM 18
#define GPIO_TEMP_READ 12

#define READ_TEMP_CMD 0x01 //Command to read temperature

int main(void)
{
    FILE *file;
    if ((file = fopen("fan_log.txt", "w")) == NULL)
    {
        printf("Failed to open file\n");
        return 1;
    }

    if (wiringPiSetup() == -1)
    {
        printf("Failed to setup wiringPi\n");
        return 1;
    }

    if (wiringPiSPISetup(MAX31855_SPI_CHANNEL, 5000000) == -1)
    {
        printf("Failed to setup SPI\n");
        return 1;
    }

    softPwmCreate(GPIO_PWM, 0, 100); //Creating a PWM pin with 0% duty cycle
    pinMode(GPIO_TEMP_READ, INPUT);  //Setting GPIO_TEMP_READ as input

    char data[3] = {0};
    char temp[2] = {0};
    int temperature;
    int fan_speed;

    while (1)
    {
        data[0] = READ_TEMP_CMD; //Setting command to read temperature
        wiringPiSPIDataRW(MAX31855_SPI_CHANNEL, data, 3); //Reading data from MAX31855

        temp[0] = data[1];
        temp[1] = data[0]; //Reversing the data to get temperature

        temperature = (int)strtol(temp, NULL, 16); //Converting hexadecimal to integer

        //Mapping temperature to fan speed
        if (temperature < 25)
        {
            fan_speed = 0;
        }
        else if (temperature >= 25 && temperature < 50)
        {
            fan_speed = (temperature - 25) * 4;
        }
        else if (temperature >= 50 && temperature < 75)
        {
            fan_speed = (temperature - 50) * 2 + 50;
