#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins for airflow sensors
#define SENSOR1_PIN 0
#define SENSOR2_PIN 1
#define SENSOR3_PIN 2

// Define GPIO pin for alarm
#define ALARM_PIN 3

// Define airflow threshold (in PPM)
#define AIRFLOW_THRESHOLD 500

// Global variable for airflow sensor readings
volatile int sensor1_value = 0;
volatile int sensor2_value = 0;
volatile int sensor3_value = 0;

// Function prototypes
int read_sensor(int pin);
void log_airflow(int sensor_id, int reading);
void activate_alarm();
void deactivate_alarm();
void signal_handler(int signal);

// Function to read airflow sensor value
int read_sensor(int pin) {
    return analogRead(pin);
}

// Function to log airflow readings to file
void log_airflow(int sensor_id, int reading) {
    FILE *fp = fopen("airflow_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening airflow_log.txt");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, Sensor %d, Airflow: %d PPM\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, sensor_id, reading);

    fclose(fp);
}

// Function to activate the alarm (set GPIO HIGH)
void activate_alarm() {
    digitalWrite(ALARM_PIN, HIGH); // Set GPIO HIGH
    printf("Alarm activated!\n");
}

// Function to deactivate the alarm (set GPIO LOW)
void deactivate_alarm() {
    digitalWrite(ALARM_PIN, LOW); // Set GPIO LOW
    printf("Alarm deactivated.\n");
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully.\n", signal);
    deactivate_alarm(); // Ensure alarm is deactivated on exit
    exit(0);
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Set pin modes
    pinMode(SENSOR1_PIN, INPUT);
    pinMode(SENSOR2_PIN, INPUT);
    pinMode(SENSOR3_PIN, INPUT);
    pinMode(ALARM_PIN, OUTPUT);

    // Initialize alarm to LOW
    digitalWrite(ALARM_PIN, LOW);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read sensor values
        sensor1_value = read_sensor(SENSOR1_PIN);
        sensor2_value = read_sensor(SENSOR2_PIN);
        sensor3_value = read_sensor(SENSOR3_PIN);

        // Log sensor readings
        log_airflow(1, sensor1_value);
        log_airflow(2, sensor2_value);
        log_airflow(3, sensor3_value);

        // Check airflow thresholds and activate alarm if needed
        if (sensor1_value < AIRFLOW_THRESHOLD || sensor2_value < AIRFLOW_THRESHOLD || sensor3_value < AIRFLOW_THRESHOLD) {
            activate_alarm();
        } else {
            deactivate_alarm();
        }

        // Wait for a short period
        delay(1000); // 1 second
    }

    return 0;
}

