#include <signal.h>
#include <pigpio.h>

// Define GPIO pins for buzzers
#define BUZZER_1_PIN 17
#define BUZZER_2_PIN 18

// Define frequency range for buzzers
#define MIN_FREQUENCY 1000
#define MAX_FREQUENCY 2000

// Define distance thresholds
#define ALARM_THRESHOLD_LOW 20
#define ALARM_THRESHOLD_MEDIUM 10

// Global variables to store distances
int distance_1 = 0;
int distance_2 = 0;

// Function prototypes
void set_buzzer_frequency(int gpio_pin, int frequency);
void play_alarm(int gpio_pin, int frequency);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    set_buzzer_frequency(BUZZER_1_PIN, 0);
    set_buzzer_frequency(BUZZER_2_PIN, 0);
    gpioTerminate();
    exit(0);
}

// Function to set the frequency of a buzzer
void set_buzzer_frequency(int gpio_pin, int frequency) {
    if (gpioHardwarePWM(gpio_pin, frequency, 500000) != 0) {
        fprintf(stderr, "Error setting PWM on GPIO %d\n", gpio_pin);
    }
}

// Function to play an alarm pattern
void play_alarm(int gpio_pin, int frequency) {
    if (frequency == 0) {
        gpioHardwarePWM(gpio_pin, 0, 0);
    } else {
        set_buzzer_frequency(gpio_pin, frequency);
        gpioDelay(200000); // Play for 200ms
        gpioHardwarePWM(gpio_pin, 0, 0);
        gpioDelay(500000); // Pause for 500ms
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as outputs
    gpioSetMode(BUZZER_1_PIN, PI_OUTPUT);
    gpioSetMode(BUZZER_2_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read distance from stdin
        int temp_distance_1, temp_distance_2;
        if (scanf("%d %d", &temp_distance_1, &temp_distance_2) != 2) {
            fprintf(stderr, "Invalid input format. Please enter two integers separated by a space.\n");
            gpioHardwarePWM(BUZZER_1_PIN, 0, 0);
            gpioHardwarePWM(BUZZER_2_PIN, 0, 0);
            continue;
        }

        // Validate distance values
        if (temp_distance_1 < 0 || temp_distance_1 > 100 || temp_distance_2 < 0 || temp_distance_2 > 100) {
            fprintf(stderr, "Invalid distance value. Please enter values between 0 and 100.\n");
            gpioHardwarePWM(BUZZER_1_PIN, 0, 0);
            gpioHardwarePWM(BUZZER_2_PIN, 0, 0);
            continue;
        }

        distance_1 = temp_distance_1;
        distance_2 = temp_distance_2;

        // Calculate frequency based on distance
        int frequency_1 = (int)(((float)distance_1 / 100.0) * (MAX_FREQUENCY - MIN_FREQUENCY)) + MIN_FREQUENCY;
        int frequency_2 = (int)(((float)distance_2 / 100.0) * (MAX_FREQUENCY - MIN_FREQUENCY)) + MIN_FREQUENCY;

        // Play alarm patterns based on distance thresholds
        if (distance_1 < ALARM_THRESHOLD_LOW) {
            play_alarm(BUZZER_1_PIN, frequency_1);
        } else if (distance_1 < ALARM_THRESHOLD_MEDIUM) {
            play_alarm(BUZZER_1_PIN, frequency_1);
        }

        if (distance_2 < ALARM_THRESHOLD_LOW) {
            play_alarm(BUZZER_2_PIN, frequency_2);
        } else if (distance_2 < ALARM_THRESHOLD_MEDIUM) {
            play_alarm(BUZZER_2_PIN, frequency_2);
        }
    }

    return 0;
}

