// Function prototypes
float read_temperature(int i2c_handle);
void control_fan(float temperature);
void log_data(float temp1, float temp2, int fan_speed);
void signal_handler(int signal);

// Function to read temperature from LM75 sensor
float read_temperature(int i2c_handle) {
    int reading;
    if (i2c_handle < 0) return -273.15; // Return absolute zero if handle is invalid

    reading = i2cReadByteData(i2c_handle, 0); // LM75 temperature register
    if (reading < 0) {
        fprintf(stderr, "Error reading temperature: %d\n", reading);
        return -273.15; // Return absolute zero on I2C error
    }

    float temp_c = (float)((int8_t)reading) + (float)(i2cReadByteData(i2c_handle, 1) >> 7) * 0.5;

    // Validate temperature range
    if (temp_c < -55.0 || temp_c > 125.0) {
        fprintf(stderr, "Invalid temperature reading: %.2f\n", temp_c);
        return -273.15; // Return absolute zero if out of range
    }

    return temp_c;
}

// Function to control fan speed based on temperature
void control_fan(float temperature) {
    int duty_cycle;

    if (temperature <= 20.0) {
        duty_cycle = 0;
    } else if (temperature >= 60.0) {
        duty_cycle = 1000000; // Max duty cycle
    } else {
        duty_cycle = (int)((temperature - 20.0) / (60.0 - 20.0) * 1000000.0);
    }

    gpioPWM(FAN_GPIO, duty_cycle);
}

// Function to log data to file
void log_data(float temp1, float temp2, int fan_speed) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(log_fp, "%d-%02d-%02d %02d:%02d:%02d, %.2f, %.2f, %d\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            temp1, temp2, fan_speed);
    fflush(log_fp); // Ensure data is written immediately
}

// Signal handler for graceful termination
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    if (i2c_handle_1 >= 0) i2cClose(i2c_handle_1);
    if (i2c_handle_2 >= 0) i2cClose(i2c_handle_2);
    if (log_fp != NULL) fclose(log_fp);
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connections
    i2c_handle_1 = i2cOpen(1, I2C_ADDR_1, 0); // Bus 1, address 0x48, flags 0
    if (i2c_handle_1 < 0) {
        fprintf(stderr, "Error opening I2C device 1: %d\n", i2c_handle_1);
        return 1;
    }

    i2c_handle_2 = i2cOpen(1, I2C_ADDR_2, 0); // Bus 1, address 0x49, flags 0
    if (i2c_handle_2 < 0) {
        fprintf(stderr, "Error opening I2C device 2: %d\n", i2c_handle_2);
        return 1;
    }

    // Configure FAN_GPIO as PWM output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQ);
    gpioSetPWMrange(FAN_GPIO, 1000000); // Set range to 1,000,000 for easier duty cycle calculation

    // Open log file
    log_fp = fopen(LOG_FILE, "a");
    if (log_fp == NULL) {
        perror("Error opening log file");
        i2cClose(i2c_handle_1);
        i2cClose(i2c_handle_2);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    float temp1, temp2, max_temp;
    int fan_speed;

    // Main loop
    while (1) {
        temp1 = read_temperature(i2c_handle_1);
        temp2 = read_temperature(i2c_handle_2);

        max_temp = temp1;
        if (temp2 > max_temp) {
            max_temp = temp2;
        }

        if (temp1 == -273.15 || temp2 == -273.15) {
            fprintf(stderr, "Error reading temperature from one or more sensors. Using previous values or defaults.\n");
        }

        control_fan(max_temp);
        fan_speed = gpioGetPWMdutycycle(FAN_GPIO);
        log_data(temp1, temp2, fan_speed);

        gpioDelay(2000000); // Wait 2 seconds
    }

    return 0; // This line will never be reached due to the infinite loop, but it's good practice to include it.
}

