    for (int i = 0; i < NUM_ZONES; i++) {
        zone = i + 1;
        int gpio_pin = (zone - 1) * 10 + 17; // Zone 1 uses GPIO 17, zone 2 uses GPIO 27, etc.
        gpioSetMode(gpio_pin, PI_OUTPUT);
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_SPEED, 0); // SPI mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "Error: SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read soil moisture for each zone
