    unsigned char spi_rx_buf[3];
    int adc_value;

    // MCP3008 command: start bit (1), single-ended mode (1), channel (3 bits), don't care (3 bits)
    spi_tx_buf[0] = 0x01; // Start bit
    spi_tx_buf[1] = (0x08 | (channel << 4)); // Single-ended mode, channel selection
    spi_tx_buf[2] = 0x00; // Don't care

    spiXfer(spi_handle, spi_tx_buf, spi_rx_buf, 3);

    // Extract ADC value (10 bits)
    adc_value = ((spi_rx_buf[1] & 0x03) << 8) + spi_rx_buf[2];

    return adc_value;
}

// Function to control the relay
void control_relay(int zone, int state) {
    if (zone < 1 || zone > NUM_ZONES) {
        fprintf(stderr, "Error: Invalid zone number: %d\n", zone);
        return;
    }

    int gpio_pin = (zone - 1) * 10 + 17; // Zone 1 uses GPIO 17, zone 2 uses GPIO 27, etc.

    if (state != 0 && state != 1) {
        fprintf(stderr, "Error: Invalid relay state: %d\n", state);
        return;
    }

    gpioWrite(gpio_pin, state);
    relay_state[zone - 1] = state;
}

// Function to log events to JSON file
void log_event(int zone, int duration) {
    json_t *root, *event;
    json_error_t error;
    FILE *file;

    // Create a new JSON object
    root = json_object();
    if (!root) {
        fprintf(stderr, "Error: Failed to create JSON object\n");
        return;
    }

    // Get the current timestamp
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    // Create a new event object
    event = json_object();
    if (!event) {
        json_decref(root);
        fprintf(stderr, "Error: Failed to create JSON event object\n");
        return;
    }

    // Add data to the event object
    json_object_set_new(event, "timestamp", json_string(timestamp));
    json_object_set_new(event, "zone", json_integer(zone));
    json_object_set_new(event, "duration", json_integer(duration));

    // Append the event to the root object
    json_array_append_new(root, event);

    // Open the log file in append mode
    file = fopen(JSON_LOG_FILE, "a");
    if (!file) {
        json_decref(root);
        fprintf(stderr, "Error: Failed to open log file: %s\n", JSON_LOG_FILE);
        return;
    }

    // Write the JSON data to the file
    if (json_dumpf(root, file, JSON_INDENT(4)) < 0) {
        json_decref(root);
        fclose(file);
        fprintf(stderr, "Error: Failed to dump JSON data\n");
        return;
    }

    // Close the file
    fclose(file);

    // Decrement the reference count of the root object
    json_decref(root);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);

    // Turn off all relays
    for (int i = 0; i < NUM_ZONES; i++) {
        control_relay(i + 1, 0);
    }

    // Close SPI connection
    spiClose(spi_handle);

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

int main() {
    int soil_moisture[NUM_ZONES];
    int zone;
    time_t start_time;
    double duration;

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins for relays as outputs
    for (int i = 0; i < NUM_ZONES; i++) {
        zone = i + 1;
        int gpio_pin = (zone - 1) * 10 + 17; // Zone 1 uses GPIO 17, zone 2 uses GPIO 27, etc.
        gpioSetMode(gpio_pin, PI_OUTPUT);
    }

    // Open SPI channel
    spi_handle = spiOpen(SPI_CHANNEL, SPI_SPEED, 0); // SPI mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "Error: SPI open failed\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read soil moisture for each zone
        for (int i = 0; i < NUM_ZONES; i++) {
            soil_moisture[i] = read_soil_moisture(i);
        }

        // Check soil moisture and control relays
        for (int i = 0; i < NUM_ZONES; i++) {
            zone = i + 1;
            if (soil_moisture[i] < SOIL_MOISTURE_THRESHOLD) {
                // Soil moisture is low, activate the relay
                if (relay_state[i] == 0) {
                    control_relay(zone, 1);
                    start_time = time(NULL);
                }
            } else {
                // Soil moisture is high, deactivate the relay
                if (relay_state[i] == 1) {
                    control_relay(zone, 0);
                    duration = difftime(time(NULL), start_time);
                    log_event(zone, (int)duration);
                }
            }
        }

        // Wait for the next reading interval
        time_sleep(SOIL_MOISTURE_READ_INTERVAL);
    }

    return 0;
