const unsigned char ssd1306_init_commands[] = {
    0xAE, // Display off
    0xD5, 0x80, // Set display clock divide ratio/oscillator frequency
    0xA8, 0x3F, // Set multiplex ratio
    0xD3, 0x00, // Set display offset
    0x40, // Set display start line
    0x8D, 0x14, // Charge pump setting
    0x20, 0x00, // Set memory addressing mode
    0xA1, // Set segment re-map (A0)
    0xC8, // Set COM output scan direction
    0xDA, 0x12, // Set COM pins hardware configuration
    0x81, 0xCF, // Set contrast control
    0xD9, 0xF1, // Set pre-charge period
    0xDB, 0x40, // Set VCOM deselect level
    0xA4, // Entire display ON (resume)
    0xA6, // Normal display
    0xAF, // Display on
};

// SSD1306 OLED display initialization commands for 64x128 OLED
const unsigned char ssd1306_init_commands_128x64[] = {
    0xAE, // Display off
    0xD5, 0x80, // Set display clock divide ratio/oscillator frequency
    0xA8, 0x3F, // Set multiplex ratio (63 for 64x128)
    0xD3, 0x00, // Set display offset
    0x40, // Set display start line
    0x8D, 0x14, // Charge pump setting
    0x20, 0x00, // Set memory addressing mode
    0xA1, // Set segment re-map (A0)
    0xC8, // Set COM output scan direction
    0xDA, 0x12, // Set COM pins hardware configuration
    0x81, 0xCF, // Set contrast control
    0xD9, 0xF1, // Set pre-charge period
    0xDB, 0x40, // Set VCOM deselect level
    0xA4, // Entire display ON (resume)
    0xA6, // Normal display
    0xAF, // Display on
};

int main(int argc, char *argv[]) {
