    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    for(;;) {
        int soil_moisture = gpioRead(SOIL_MOISTURE_SENSOR_PIN);

        if (soil_moisture < 0) {
            printf("Failed to read soil moisture sensor\n");
            gpioTerminate();
            return 1;
        }

        time_t now = time(NULL);
        char *timestamp = ctime(&now);

        char data[100];
        sprintf(data, "%s, %d\n", timestamp, soil_moisture);

        writeToFile(data);

        if (soil_moisture < LOW_SOIL_MOISTURE_THRESHOLD) {
            gpioWrite(RELAY_PIN, 1);
        } else {
            gpioWrite(RELAY_PIN, 0);
