    if (pthread_create(&sensor_thread, NULL, sensor_reading_thread, NULL) != 0) {
        syslog(LOG_ERR, "Failed to create sensor reading thread.");
        return 1;
    }
    if (pthread_create(&mqtt_thread, NULL, mqtt_publishing_thread, NULL) != 0) {
