// DHT22 reading function
int read_sensor_data(int gpio, sensor_data_t *data) {
    int result = -1;
    int data_bits[40];
    int bit_index = 0;
    int i, j;
    int data_buffer[5] = {0, 0, 0, 0, 0};

    gpioSetMode(gpio, PI_INPUT);

    // Wait for DHT22 to pull low
    int count = 0;
    while (gpioRead(gpio) == 1 && count < 1000) {
        gpioDelay(1); // Small delay
        count++;
    }
    if (count >= 1000) {
        fprintf(stderr, "Timeout waiting for DHT22 pull-down\n");
        return -1;
    }

    // Wait for DHT22 to pull high
    count = 0;
    while (gpioRead(gpio) == 0 && count < 1000) {
        gpioDelay(1); // Small delay
        count++;
    }
    if (count >= 1000) {
        fprintf(stderr, "Timeout waiting for DHT22 pull-up\n");
        return -1;
    }

    // Read 40 bits of data
    for (i = 0; i < 40; i++) {
        count = 0;
        // Wait for DHT22 to pull low
        while (gpioRead(gpio) == 0 && count < 1000) {
            gpioDelay(1); // Small delay
            count++;
        }
        if (count >= 1000) {
            fprintf(stderr, "Timeout waiting for DHT22 bit start\n");
            return -1;
        }

        // Wait for DHT22 to pull high
        count = 0;
        while (gpioRead(gpio) == 1 && count < 1000) {
            gpioDelay(1); // Small delay
            count++;
        }
        if (count >= 1000) {
            fprintf(stderr, "Timeout waiting for DHT22 bit end\n");
            return -1;
        }

        // Determine the length of the high pulse
        count = 0;
        while (gpioRead(gpio) == 0 && count < 1000) {
            gpioDelay(1); // Small delay
            count++;
        }
        if (count >= 1000) {
            fprintf(stderr, "Timeout waiting for DHT22 bit pulse\n");
            return -1;
        }

        if (count > 20) {
            data_bits[bit_index] = 1; // High pulse longer than 20 us
        } else {
            data_bits[bit_index] = 0; // High pulse shorter than 20 us
        }

        bit_index++;
    }

    // Convert the data bits into bytes
    for (i = 0; i < 40; i += 8) {
        int byte = 0;
        for (j = 0; j < 8; j++) {
            byte <<= 1;
            if (data_bits[i + j] == 1) {
                byte++;
            }
        }
        data_buffer[i / 8] = byte;
    }

    // Validate checksum
    if ((data_buffer[0] + data_buffer[1] + data_buffer[2] + data_buffer[3]) != data_buffer[4]) {
        fprintf(stderr, "DHT22 checksum error\n");
        return -1;
    }

    // Convert data to temperature and humidity
    data->humidity = (float)((data_buffer[0] << 8) + data_buffer[1]) / 10.0;
    data->temperature = (float)(((data_buffer[2] & 0x7F) << 8) + data_buffer[3]) / 10.0;
    if (data_buffer[2] & 0x80) {
        data->temperature *= -1.0;
    }

    result = 0; // Success

    return result;
}

