    if (!root) {
        fprintf(stderr, "Error parsing config file %s: %s\n", filename, error.text);
        return -1;
    }

    temp_threshold = json_object_get(root, "temperature_threshold");
    if (!json_is_real(temp_threshold)) {
        fprintf(stderr, "Error: temperature_threshold is not a number\n");
        json_decref(root);
        return -1;
    }
    thresholds->temperature_threshold = json_real_value(temp_threshold);

    humidity_threshold = json_object_get(root, "humidity_threshold");
    if (!json_is_real(humidity_threshold)) {
        fprintf(stderr, "Error: humidity_threshold is not a number\n");
        json_decref(root);
        return -1;
    }
    thresholds->humidity_threshold = json_real_value(humidity_threshold);

    json_decref(root);

    return 0;
}

