    fp = fopen(filename, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    fprintf(fp, "%s Temperature: %.1f C, Humidity: %.1f %%\n", timestamp, data.temperature, data.humidity);

    if (fclose(fp) != 0) {
        perror("Error closing log file");
        return -1;
    }

    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    gpioTerminate();
    exit(0);
}

int main() {
    sensor_data_t sensor_data;

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Parse configuration file
    if (parse_config_file(CONFIG_FILE, &thresholds) != 0) {
        fprintf(stderr, "Failed to parse configuration file, using default thresholds\n");
        thresholds.temperature_threshold = 25.0;
        thresholds.humidity_threshold = 60.0;
    }

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("DHT22 sensor monitoring started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read sensor data
        if (read_sensor_data(SENSOR_GPIO, &sensor_data) == 0) {
            // Check thresholds and log data if necessary
            if (sensor_data.temperature > thresholds.temperature_threshold ||
                sensor_data.humidity > thresholds.humidity_threshold) {
                if (log_data(LOG_FILE, sensor_data) != 0) {
                    fprintf(stderr, "Error logging data\n");
                }
            }
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        gpioDelay(5000); // Wait 5 seconds
    }

    gpioTerminate();

    return 0;
}

