        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    int fd = wiringPiI2CSetup(SHT31_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    uint16_t raw_temperature, raw_humidity;

    if (read_sensor_data(fd, &raw_temperature, &raw_humidity) == 0) {
        SensorData data = convert_data(raw_temperature, raw_humidity);
        char *json_string = format_json(data.temperature, data.humidity);
        if (json_string != NULL) {
            if (log_data(json_string) != 0) {
