// SHT31-DIS command for high repeatability measurement
#define SHT31_MEASURE_HIGH_REP 0x2C06

// Global variables
static volatile int keepRunning = 1;
static int i2c_fd = -1;
static const char *log_file_path = "environmental_log.json";

// Structure to hold sensor data
typedef struct {
    float temperature;
    float humidity;
} sensor_data_t;

// Function prototypes
int init_i2c(int addr);
int read_sensor_data(int fd, float *temperature, float *humidity);
json_t *create_json_log(float temperature, float humidity);
int write_json_to_file(const char *filepath, const char *json_string);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    keepRunning = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

// Initializes I2C communication
int init_i2c(int addr) {
    int fd = wiringPiI2CSetup(addr);
    if (fd == -1) {
        perror("wiringPiI2CSetup failed");
        return -1;
    }
    return fd;
}

// Reads temperature and humidity data from the SHT31-DIS sensor
int read_sensor_data(int fd, float *temperature, float *humidity) {
    unsigned char data[6];
    int result;

    // Send measurement command
    result = wiringPiI2CWriteReg16(fd, 0x00, SHT31_MEASURE_HIGH_REP);
    if (result == -1) {
        perror("wiringPiI2CWriteReg16 failed");
        return -1;
    }

    // Wait for measurement to complete (at least 10ms)
    delay(20);

    // Read 6 bytes of data
    for (int i = 0; i < 6; i++) {
        data[i] = wiringPiI2CRead(fd);
        if (data[i] == -1) {
            perror("wiringPiI2CRead failed");
            return -1;
        }
    }

    // Convert data to temperature and humidity
    unsigned int temperature_raw = (data[0] << 8) | data[1];
    unsigned int humidity_raw = (data[3] << 8) | data[4];

    *temperature = -45.0 + (175.0 * (float)temperature_raw / 65535.0);
    *humidity = 100.0 * (float)humidity_raw / 65535.0;

    return 0;
}

// Creates a JSON log entry
json_t *create_json_log(float temperature, float humidity) {
    json_t *root = json_object();
    json_t *timestamp = json_string(ctime(&(time_t){time(NULL)}));
    json_t *temperature_obj = json_real(temperature);
    json_t *humidity_obj = json_real(humidity);

    json_object_set_new(root, "timestamp", timestamp);
    json_object_set_new(root, "temperature", temperature_obj);
    json_object_set_new(root, "humidity", humidity_obj);

    return root;
}

// Writes JSON data to a file
int write_json_to_file(const char *filepath, const char *json_string) {
    int fd = open(filepath, O_WRONLY | O_CREAT | O_APPEND, 0644);
    if (fd == -1) {
        perror("open failed");
        return -1;
    }

    ssize_t bytes_written = write(fd, json_string, strlen(json_string));
    if (bytes_written == -1) {
        perror("write failed");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
