    }

    // Initialize I2C
    i2c_fd = init_i2c(SHT31_ADDR);
    if (i2c_fd == -1) {
        return 1;
    }

    printf("Environmental data logging started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        sensor_data_t sensor_data;
        json_t *json_log;
        char *json_string;

        // Read sensor data
        if (read_sensor_data(i2c_fd, &sensor_data.temperature, &sensor_data.humidity) == 0) {
            // Create JSON log
            json_log = create_json_log(sensor_data.temperature, sensor_data.humidity);
            if (json_log != NULL) {
                // Convert JSON to string
                json_string = json_dumps(json_log, JSON_COMPACT);
                if (json_string != NULL) {
                    // Write JSON to file
                    if (write_json_to_file(log_file_path, json_string) == 0) {
                        printf("Logged data: Temperature = %.2f, Humidity = %.2f\n", sensor_data.temperature, sensor_data.humidity);
                    } else {
                        fprintf(stderr, "Failed to write JSON to file.\n");
                    }
                    free(json_string);
                } else {
                    fprintf(stderr, "Failed to convert JSON to string.\n");
                }
                json_decref(json_log);
            } else {
                fprintf(stderr, "Failed to create JSON log.\n");
            }
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        // Wait for 5 seconds
        delay(5000);
    }

    // Clean up
    close(i2c_fd);
    printf("Environmental data logging stopped.\n");

    return 0;
}

