#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <syslog.h>

#define RELAY_PIN 17
#define TOUCH_PIN 4
#define DEBOUNCE_DELAY 200 // in milliseconds

int main(void) {
    int relayState = 0;
    int lastTouchState = 0;
    int currentTouchState = 0;
    time_t lastDebounceTime = 0;

    // Start syslog
    openlog("relay_control", LOG_PID, LOG_USER);

    if (wiringPiSetup() == -1) {
        syslog(LOG_ERR, "Unable to setup wiringPi: %s", strerror(errno));
        exit(1);
    }

    if (wiringPiSetupGpio() == -1) {
        syslog(LOG_ERR, "Unable to setup wiringPi with GPIO: %s", strerror(errno));
        exit(1);
    }

    pinMode(RELAY_PIN, OUTPUT);
    pinMode(TOUCH_PIN, INPUT);

    // Initialize relay to off
    digitalWrite(RELAY_PIN, LOW);

    while (1) {
        currentTouchState = digitalRead(TOUCH_PIN);

        if (currentTouchState != lastTouchState) {
            lastDebounceTime = millis();
        }

        if ((millis() - lastDebounceTime) > DEBOUNCE_DELAY) {
            if (currentTouchState == HIGH) {
                relayState = !relayState;
                syslog(LOG_INFO, "Relay state changed to: %d", relayState);
            }
        }

        digitalWrite(RELAY_PIN, relayState);
        lastTouchState = currentTouchState;

        delay(10);
    }

    return 0;
}

