#define D7S_REG_X_L 0x02

// Function to handle I2C errors
void handle_i2c_error(int status, const char *message) {
    if (status < 0) {
        fprintf(stderr, "I2C Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
        exit(EXIT_FAILURE);
    }
}

// Function to initialize the D7S sensor
int d7s_init(int fd) {
    int id = wiringPiI2CReadReg8(fd, D7S_REG_ID);
    if (id < 0) {
        handle_i2c_error(id, "Failed to read sensor ID");
        return -1;
    }
    if (id != 0x4F) { // Expected ID.  Adjust if needed.
        fprintf(stderr, "Error: Incorrect sensor ID: 0x%02X\n", id);
        return -1;
    }
    printf("D7S sensor initialized successfully.\n");
    return 0;
}

// Function to read acceleration data from the D7S sensor
int d7s_read_acceleration(int fd, int16_t *x, int16_t *y, int16_t *z) {
    int x_raw, y_raw, z_raw;

    x_raw = wiringPiI2CReadReg16(fd, D7S_REG_X_L);
    handle_i2c_error(x_raw, "Failed to read X acceleration");
    *x = (int16_t)x_raw; // No endian swap needed based on documentation

    y_raw = wiringPiI2CReadReg16(fd, 0x04);
    handle_i2c_error(y_raw, "Failed to read Y acceleration");
    *y = (int16_t)y_raw;

    z_raw = wiringPiI2CReadReg16(fd, 0x06);
    handle_i2c_error(z_raw, "Failed to read Z acceleration");
    *z = (int16_t)z_raw;

    return 0;
}

// Function to check if the vibration threshold is exceeded
int d7s_check_threshold(int16_t x, int16_t y, int16_t z, int threshold) {
    if (abs(x) > threshold || abs(y) > threshold || abs(z) > threshold) {
        return 1;
    }
    return 0;
}

// Function to log seismic event data to a CSV file
void log_seismic_event(int16_t x, int16_t y, int16_t z, const char *filename) {
    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s: %s\n", filename, strerror(errno));
        return;
    }

    fprintf(fp, "%s,%d,%d,%d\n", timestamp, x, y, z);
