#include <signal.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

// Constants
#define MOTION_SENSOR_GPIO 17
#define BUZZER_GPIO 27
#define SERVER_PORT 12345
#define BUZZER_DURATION_MS 1000
#define SERVER_IP "127.0.0.1" // Replace with your server's IP address

// Global variables
FILE *log_file = NULL;
int socket_fd = 0;
volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully.\n", signal);
    program_running = 0;
}

// Function to log motion detection events
void log_motion(const char *timestamp) {
    if (log_file != NULL) {
        fprintf(log_file, "%s Motion detected\n", timestamp);
        fflush(log_file); // Ensure immediate write to file
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Function to send motion detection message to the server
void send_motion_alert(const char *timestamp) {
    struct sockaddr_in server_addr;
    char message[256];

    // Create socket
    socket_fd = socket(AF_INET, SOCK_DGRAM, 0);
    if (socket_fd < 0) {
        perror("Error creating socket");
        return;
    }

    // Configure server address
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(SERVER_PORT);
    if (inet_pton(AF_INET, SERVER_IP, &server_addr.sin_addr) <= 0) {
        perror("Invalid address/ Address not supported");
        close(socket_fd);
        return;
    }

    // Prepare message
    snprintf(message, sizeof(message), "Motion detected at: %s", timestamp);

    // Send message
    if (sendto(socket_fd, message, strlen(message), 0, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Error sending message");
    }

    close(socket_fd);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(MOTION_SENSOR_GPIO, PI_INPUT);
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);

    // Open log file
    log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    int last_motion_state = 0; // Debouncing
    time_t last_motion_time = 0;

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int motion_detected = gpioRead(MOTION_SENSOR_GPIO);

        // Sensor validation and debouncing
        if (motion_detected == 0 || motion_detected == 1) {
            if (motion_detected && !last_motion_state) {
                time_t current_time = time(NULL);
                if (difftime(current_time, last_motion_time) > 2) { // Debounce for 2 seconds
                    // Get current timestamp
                    char timestamp[20];
                    struct tm *tm_info = localtime(&current_time);
                    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm_info);

                    // Log motion
                    log_motion(timestamp);

                    // Activate buzzer
