#define VL53L1X_I2C_ADDR 0x29
#define VL53L1X_REG_IDENTIFICATION_MODEL_ID 0x010F
#define VL53L1X_REG_SYSTEM_START 0x0000
#define VL53L1X_REG_RESULT_RANGE_STATUS 0x0014
#define VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0 0x0062
#define VL53L1X_REG_SYSTEM_SEQUENCE_CONFIG 0x0001
#define VL53L1X_REG_SYSTEM_INTERRUPT_CLEAR 0x0002
#define VL53L1X_REG_SYSTEM_MODE_GPIO0 0x0060
#define VL53L1X_REG_RESULT_RANGE_STATUS 0x0014

#define VL53L1X_REG_SYSTEM_SEQUENCE_CONFIG_MULTI_RANGES 0x0002
#define VL53L1X_REG_RESULT_RANGE_STATUS_V2_RANGE_READY 0x0001

// Global variables
static int i2c_handle;
static volatile int running = 1;
static FILE *log_file = NULL;

// Function prototypes
int initialize_gpio();
int initialize_i2c();
int initialize_vl53l1x();
int read_vl53l1x_distance(int *distance);
int handle_motion_detection(int pir_value);
void log_distance(int distance);
void signal_handler(int signal);

// Structure for VL53L1X configuration
typedef struct {
    uint8_t system_sequence_config;
    uint8_t system_mode_gpio0;
    uint8_t interrupt_clear;
    uint8_t sequence_config_multi_ranges;
} vl53l1x_config_t;

// Default VL53L1X configuration
const vl53l1x_config_t default_config = {
    .system_sequence_config = 0x00,
    .system_mode_gpio0 = 0x02, // Single shot mode
    .interrupt_clear = 0x01,
    .sequence_config_multi_ranges = 0x00,
};

int main() {
    // Initialize GPIO and I2C
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Error initializing GPIO. Exiting.\n");
        return 1;
    }
    if (initialize_i2c() != 0) {
        fprintf(stderr, "Error initializing I2C. Exiting.\n");
        return 1;
    }

    // Initialize VL53L1X
    if (initialize_vl53l1x() != 0) {
        fprintf(stderr, "Error initializing VL53L1X. Exiting.\n");
        return 1;
    }

    // Open log file
    log_file = fopen("distance_log.csv", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);

    printf("Monitoring for motion...\n");

    // Main loop
    while (running) {
        int pir_value = gpioRead(PIR_GPIO);
        if (pir_value == 1) {
            printf("Motion detected!\n");
            int distance;
            if (read_vl53l1x_distance(&distance) == 0) {
                log_distance(distance);
                printf("Distance: %d mm\n", distance);
            } else {
                fprintf(stderr, "Error reading distance.\n");
            }
            gpioDelay(100); // Debounce delay
        } else {
            gpioDelay(10); // Small delay to reduce CPU usage
        }
    }

    // Clean up
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();

    return 0;
}

int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetPullUpDown(PIR_GPIO, PI_PUD_DOWN); // Use pull-down resistor

    return 0;
}

int initialize_i2c() {
    i2c_handle = i2cOpen(1, VL53L1X_I2C_ADDR, 0); // Bus 1, address 0x29, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        return -1;
    }
    return 0;
}

int initialize_vl53l1x() {
    // Check device ID
    int model_id = i2cReadByteData(i2c_handle, VL53L1X_REG_IDENTIFICATION_MODEL_ID);
    if (model_id < 0) {
        fprintf(stderr, "Error reading model ID: %d\n", model_id);
        return -1;
    }
    if (model_id != 0xEACC) {
        fprintf(stderr, "Incorrect model ID: 0x%X\n", model_id);
        return -1;
    }

    // Configure VL53L1X (example configuration)
    if (i2cWriteByteData(i2c_handle, VL53L1X_REG_SYSTEM_MODE_GPIO0, default_config.system_mode_gpio0) < 0) {
        perror("Error writing to system mode register");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, VL53L1X_REG_SYSTEM_SEQUENCE_CONFIG, default_config.system_sequence_config) < 0) {
        perror("Error writing to system sequence config register");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, VL53L1X_REG_SYSTEM_SEQUENCE_CONFIG_MULTI_RANGES, default_config.sequence_config_multi_ranges) < 0) {
        perror("Error writing to system sequence config multi ranges register");
        return -1;
    }

    // Start continuous ranging
    if (i2cWriteByteData(i2c_handle, VL53L1X_REG_SYSTEM_START, 0x01) < 0) {
        perror("Error starting VL53L1X");
        return -1;
    }

    return 0;
}

int read_vl53l1x_distance(int *distance) {
    int status;

    // Wait for data ready (using polling)
    int timeout = 1000; // Timeout after 1000 attempts
    while (timeout > 0) {
        status = i2cReadByteData(i2c_handle, VL53L1X_REG_RESULT_RANGE_STATUS);
        if (status < 0) {
            perror("Error reading range status");
            return -1;
        }
        if ((status & VL53L1X_REG_RESULT_RANGE_STATUS_V2_RANGE_READY) == VL53L1X_REG_RESULT_RANGE_STATUS_V2_RANGE_READY) {
            break; // Data ready
        }
        gpioDelay(10); // Small delay
        timeout--;
    }

    if (timeout == 0) {
        fprintf(stderr, "Timeout waiting for data ready\n");
        return -1;
    }

    // Read distance
    int dist = i2cReadWordData(i2c_handle, VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0);
    if (dist < 0) {
        perror("Error reading distance");
        return -1;
    }

    *distance = dist & 0xFFFF; // Extract 16-bit distance value

    return 0;
}

void log_distance(int distance) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s,%d\n", timestamp, distance);
    fflush(log_file); // Ensure data is written to disk
}

void signal_handler(int signal) {
    printf("Caught signal %d, exiting...\n", signal);
    running = 0;
}

