// Configuration
#define PIR_PIN 17      // WiringPi pin number for PIR sensor
#define LED_PIN 18      // WiringPi pin number for LED
#define SERVER_IP "127.0.0.1" // Server IP address (loopback for testing)
#define SERVER_PORT 5000    // Server port number

// Global variables (volatile for signal handling)
volatile sig_atomic_t program_running = 1;

// Function prototypes
void motionDetected(void);
void toggleLED(int pin);
void sendMotionData(void);
void signalHandler(int signum);

// Signal handler function
void signalHandler(int signum) {
    if (signum == SIGINT) {
        fprintf(stdout, "\nCaught SIGINT, exiting gracefully.\n");
        program_running = 0;
        // Disable interrupts
        wiringPiISR(PIR_PIN, INT_EDGE_RISING, NULL);
        // Turn off LED
        digitalWrite(LED_PIN, LOW);
        exit(0);
    }
}

// Function to toggle the LED state
void toggleLED(int pin) {
    static int led_state = LOW; // Maintain LED state
    led_state = (led_state == LOW) ? HIGH : LOW;
    digitalWrite(pin, led_state);
}

// Function to send motion data to the server via UDP
void sendMotionData(void) {
    int sockfd;
    struct sockaddr_in servaddr;
    char message[256];
    time_t now;
    char *timestamp;

    // Get current timestamp
    now = time(NULL);
    timestamp = ctime(&now);
    timestamp[strlen(timestamp) - 1] = '\0'; // Remove trailing newline

    // Construct the message
    snprintf(message, sizeof(message), "Motion detected at: %s", timestamp);

    // Create socket
    if ((sockfd = socket(AF_INET, SOCK_DGRAM, 0)) < 0) {
        fprintf(stderr, "Socket creation failed: %s\n", strerror(errno));
        return;
    }

    memset(&servaddr, 0, sizeof(servaddr));
    servaddr.sin_family = AF_INET;
    servaddr.sin_port = htons(SERVER_PORT);

    // Convert IPv4 and IPv6 addresses from text to binary form
    if (inet_pton(AF_INET, SERVER_IP, &servaddr.sin_addr) <= 0) {
        fprintf(stderr, "Invalid address / Address not supported: %s\n", strerror(errno));
        close(sockfd);
        return;
    }

    // Send the message
    if (sendto(sockfd, (const char *)message, strlen(message), 0, (const struct sockaddr *)&servaddr, sizeof(servaddr)) < 0) {
        fprintf(stderr, "Sendto failed: %s\n", strerror(errno));
        close(sockfd);
        return;
    }

    fprintf(stdout, "Motion data sent to server: %s\n", message);

    close(sockfd);
}

// Interrupt handler function for motion detection
void motionDetected(void) {
    fprintf(stdout, "Motion detected!\n");
    toggleLED(LED_PIN);
    sendMotionData();
}

int main(void) {
    // Set up signal handler for Ctrl+C
    if (signal(SIGINT, signalHandler) == SIG_ERR) {
        fprintf(stderr, "Failed to register signal handler for SIGINT.\n");
        return 1;
    }

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "WiringPi initialization failed: %s\n", strerror(errno));
        return 1;
    }

    // Set PIR pin as input
    pinMode(PIR_PIN, INPUT);

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW); // Initially turn off the LED

    // Attach interrupt handler to PIR pin
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return 1;
    }

    fprintf(stdout, "Motion detection service started. Press Ctrl+C to exit.\n");

    // Main loop (keep the program running until a signal is received)
    while (program_running) {
        delay(100); // Reduce CPU usage
    }

    return 0;
}

