## Solution

To solve this problem, we can use the pigpio library for GPIO control and the BH1750 library for sensor communication.

This code assumes that you have the `pigpio` library installed on your Raspberry Pi and that you have compiled the BH1750 library (if you haven't, you can find it here: https://github.com/claws/BH1750).

```c
#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <bh1750.h>
#include <time.h>

#define BH1750_ADDR 0x23 // Default I2C Address
#define LED_PIN 24      // GPIO24 for LED strip
#define DELAY_TIME 500   // Delay time in ms

void error_exit(const char *message)
{
    perror(message);
    exit(EXIT_FAILURE);
}

int main()
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialization failed\n");
        return 1;
    }

    // Open BH1750 sensor
    bh1750Sensor_t sensor = bh1750Sensor(BH1750_ADDR);
    if (sensor < 0)
    {
        error_exit("Failed to initialize BH1750 sensor");
    }

    // Set sensor mode
    if (bh1750SetMode(sensor, BH1750_CONTINUOUS_HIGH_RES_MODE) < 0)
    {
        error_exit("Failed to set sensor mode");
    }

    // Open LED pin
    if (gpioSetMode(LED_PIN, PI_OUTPUT) < 0)
    {
        error_exit("Failed to set LED pin mode");
    }

    FILE *logFile = fopen("light_log.txt", "w");
    if (logFile == NULL)
    {
        error_exit("Failed to open log file");
    }

    // Initial light value
    int lastLightValue = bh1750ReadLightLevel(sensor);
    if (lastLightValue < 0)
    {
        error_exit("Failed to read light level");
    }

    while (1)
    {
        int currentLightValue = bh1750ReadLightLevel(sensor);
        if (currentLightValue < 0)
        {
            error_exit("Failed to read light level");
