#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <bh1750.h>
#include <time.h>

#define BH1750_ADDR 0x23 // Default I2C Address
#define LED_PIN 24      // GPIO24 for LED strip
#define DELAY_TIME 500   // Delay time in ms

void error_exit(const char *message)
{
    perror(message);
    exit(EXIT_FAILURE);
}

int main()
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialization failed\n");
        return 1;
    }

    // Open BH1750 sensor
    bh1750Sensor_t sensor = bh1750Sensor(BH1750_ADDR);
    if (sensor < 0)
    {
        error_exit("Failed to initialize BH1750 sensor");
    }

    // Set sensor mode
    if (bh1750SetMode(sensor, BH1750_CONTINUOUS_HIGH_RES_MODE) < 0)
    {
        error_exit("Failed to set sensor mode");
    }

    // Open LED pin
    if (gpioSetMode(LED_PIN, PI_OUTPUT) < 0)
    {
        error_exit("Failed to set LED pin mode");
    }

    FILE *logFile = fopen("light_log.txt", "w");
    if (logFile == NULL)
    {
        error_exit("Failed to open log file");
    }

    // Initial light value
    int lastLightValue = bh1750ReadLightLevel(sensor);
    if (lastLightValue < 0)
    {
        error_exit("Failed to read light level");
    }

    while (1)
    {
        int currentLightValue = bh1750ReadLightLevel(sensor);
        if (currentLightValue < 0)
        {
            error_exit("Failed to read light level");
        }

        // If there's a significant light change
        if (abs(currentLightValue - lastLightValue) >= 5)
        {
            // Log timestamped lux values
            time_t now = time(NULL);
            struct tm *ptm = localtime(&now);
            char timestamp[32];
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", ptm);
            fprintf(logFile, "%s: %d lux\n", timestamp, currentLightValue);
            fflush(logFile);

            // Adjust LED brightness
            gpioPWM(LED_PIN, currentLightValue * 255 / 65535);

            lastLightValue = currentLightValue;
        }

        // Delay
        gpioDelay(DELAY_TIME);
    }

    // Close file and cleanup
    fclose(logFile);
    bh1750SensorDelete(sensor);
    gpioTerminate();

    return 0;
}

