            if (result != 0) {
                fprintf(stderr, "Error setting LED brightness: %d\n", result);
            }

            // Log data
            log_light_data(lux_value);
        } else {
            fprintf(stderr, "Error reading lux value\n");
        }

        // Delay
        gpioDelay(100000); // 100ms
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

// Initialize I2C communication
int initialize_i2c(int *handle, int address) {
    *handle = i2cOpen(1, address, 0); // I2C bus 1, address, flags (none)
    if (*handle < 0) {
        fprintf(stderr, "Error opening I2C: %s\n", strerror(errno));
        return -1;
    }

    // Set BH1750 to continuous high-resolution mode
    if (i2cWriteByte(*handle, CONTINUOUS_HIGH_RES_MODE) != 0) {
        fprintf(stderr, "Error setting BH1750 mode: %s\n", strerror(errno));
        i2cClose(*handle);
        return -1;
    }

    return *handle;
}

// Read lux value from BH1750
int read_lux(int handle, float *lux) {
    unsigned char data[2];
    int result;

    result = i2cReadI2CBlockData(handle, 0x00, (char *)data, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading I2C data: %s\n", strerror(errno));
        return -1;
    }

    // Convert raw data to lux
    *lux = (float)((data[0] << 8) | data[1]) / 1.2;

    return 0;
}

// Map lux value to brightness (0-255)
int map_lux_to_brightness(float lux) {
    // Linear mapping (adjust as needed)
    int brightness = (int)(lux * 2.55);

    // Clamp to 0-255
    if (brightness < 0) brightness = 0;
    if (brightness > 255) brightness = 255;

    return brightness;
}

// Set LED brightness using PWM
int set_led_brightness(int pin, int brightness) {
    if (gpioPWM(pin, brightness) != 0) {
        fprintf(stderr, "Error setting PWM: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Log light data to file
int log_light_data(float lux) {
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    static float last_lux = 0.0;

    // Open file in append mode
    fp = fopen(config.log_file, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return -1;
    }

    // Check for significant change
    if (abs(lux - last_lux) >= config.lux_threshold) {
        // Format timestamp
        char timestamp[20];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

        // Write data to file
        fprintf(fp, "%s, %.2f\n", timestamp, lux);
        fflush(fp); // Ensure data is written immediately

        last_lux = lux;
    }

    fclose(fp);
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Received signal %d, shutting down...\n", signal);
    running = 0;
}

// Cleanup function
void cleanup() {
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    printf("Program terminated.\n");
}

