    printf("Cleaning up and exiting...\n");

    // Close I2C connection
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }

    // Clear LCD display
    if (lcd_handle >= 0) {
        lcd_clear();
    }

    // Release file lock and close log file
    if (log_fd >= 0) {
        flock(log_fd, LOCK_UN);
        close(log_fd);
    }

    // Free JSON array
    if (log_array != NULL) {
        json_decref(log_array);
    }

