            retries++;
            gpioDelay(100); // Wait before retrying
        }
    }
    return -1; // Failure
}

int read_sht31(float *temperature, float *humidity) {
    char write_data[2] = {(SHT31_MEASUREMENT_COMMAND >> 8) & 0xFF, SHT31_MEASUREMENT_COMMAND & 0xFF};
    char read_data[6];
    int result;

    result = i2cWriteDevice(i2c_handle, write_data, 2);
    if (result != 2) {
        fprintf(stderr, "Error writing to SHT31: %d\n", result);
        return -1;
    }

    gpioDelay(20); // Wait for measurement (adjust if needed)

    result = i2cReadDevice(i2c_handle, read_data, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from SHT31: %d\n", result);
        return -1;
    }

    // Convert data
    uint16_t temp_raw = (read_data[0] << 8) | read_data[1];
    uint16_t hum_raw = (read_data[3] << 8) | read_data[4];

    *temperature = -45.0 + (175.0 * (float)temp_raw / 65535.0);
    *humidity = 100.0 * (float)hum_raw / 65535.0;

    // Validate readings
    if (*temperature < -40.0 || *temperature > 125.0) {
        fprintf(stderr, "Warning: Temperature out of range: %.2f\n", *temperature);
        return -1;
    }
    if (*humidity < 0.0 || *humidity > 100.0) {
        fprintf(stderr, "Warning: Humidity out of range: %.2f\n", *humidity);
        return -1;
    }

    return 0;
}

void display_data(float temperature, float humidity) {
    if (lcd_handle < 0) return; // Don't attempt to display if LCD init failed

    char temp_str[20];
    char hum_str[20];

    snprintf(temp_str, sizeof(temp_str), "Temp: %.2f C", temperature);
    snprintf(hum_str, sizeof(hum_str), "Hum: %.2f %%", humidity);

    lcd_clear();
    lcd_string(temp_str);
    lcd_byte(0xC0, LCD_CMD); // Move cursor to second line
    lcd_string(hum_str);
}

void log_data(float temperature, float humidity) {
    // Get current timestamp
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", t); // ISO 8601

    // Create JSON object
    json_t *reading = json_object();
    json_object_set_new(reading, "timestamp", json_string(timestamp));
    json_object_set_new(reading, "temperature", json_real(temperature));
    json_object_set_new(reading, "humidity", json_real(humidity));

    // Append to JSON array
    json_array_append_new(log_array, reading);

    // Open log file with locking
    log_fd = open(LOG_FILE, O_WRONLY | O_CREAT | O_APPEND, 0644);
    if (log_fd < 0) {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return;
    }

    // Acquire exclusive lock
    if (flock(log_fd, LOCK_EX) < 0) {
        fprintf(stderr, "Failed to acquire lock on log file: %s\n", strerror(errno));
        close(log_fd);
        return;
    }

    // Write JSON data to file
    FILE *log_file = fdopen(log_fd, "w");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file as FILE*: %s\n", strerror(errno));
        flock(log_fd, LOCK_UN);
        close(log_fd);
        return;
    }
    json_dumpf(log_array, log_file, JSON_INDENT(4)); // Pretty print
    fprintf(log_file, "\n"); // Add newline

    // Release lock and close file
    fclose(log_file);
    flock(log_fd, LOCK_UN);
    close(log_fd);
    log_fd = -1; // Reset log_fd
}

void update_data_callback() {
    float temperature, humidity;

    if (read_sht31(&temperature, &humidity) == 0) {
        printf("Temperature: %.2f C, Humidity: %.2f %%\n", temperature, humidity);
        display_data(temperature, humidity);
        log_data(temperature, humidity);
    }
}

// LCD functions (Simplified for brevity, adjust as needed)
void lcd_byte(int bits, int mode) {
    // Send byte to data pins
    // bits = the data
    // mode = 1 for data, 0 for command

    int bits_high = mode | (bits & 0xF0) | LCD_BACKLIGHT;
    int bits_low = mode | ((bits << 4) & 0xF0) | LCD_BACKLIGHT;

    i2cWriteByteData(lcd_handle, bits_high,0); // original code
    gpioDelay(1); // Original code
