    i2c_handle = i2cOpen(1, SHT31_ADDR, 0); // Bus 1, address 0x44, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        return -1;
    }
    return 0;
}

// Initialize LCD
int init_lcd() {
    lcd_handle = i2cOpen(1, LCD1602_ADDR, 0); // Bus 1, address 0x27 or 0x3F, no flags
    if (lcd_handle < 0) {
        fprintf(stderr, "Error opening LCD I2C: %d\n", lcd_handle);
        return -1;
    }

    // Initialization sequence (adjust as needed based on your LCD type)
    usleep(15000); // Wait for more than 15ms after power-on
    i2cWriteByteData(lcd_handle, LCD_CMD_REG, 0x33); // Initialize
    usleep(4500);   // Wait for more than 4.1ms
    i2cWriteByteData(lcd_handle, LCD_CMD_REG, 0x32); // Initialize
    usleep(15000); // Wait for more than 15ms

    // Configure display and cursor
    i2cWriteByteData(lcd_handle, LCD_CMD_REG, LCD_FUNCTIONSET | LCD_2LINE | LCD_5x8DOTS);
    i2cWriteByteData(lcd_handle, LCD_CMD_REG, LCD_DISPLAYCONTROL | LCD_DISPLAYON | LCD_CURSOROFF | LCD_BLINKOFF);
    i2cWriteByteData(lcd_handle, LCD_CMD_REG, LCD_ENTRYMODESET | LCD_ENTRYLEFT | LCD_ENTRYSHIFTDECREMENT);

    return 0;
}

