    if (result < 0) {
        fprintf(stderr, "Error writing to I2C: %d\n", result);
        return -1;
    }

    // Wait for measurement to complete (adjust as needed)
    gpioDelay(100000); // 100ms

    // Read 6 bytes of data
    result = i2cReadI2CBlockData(i2c_handle, 0, buffer, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from I2C: %d\n", result);
        return -1;
    }

    // Convert data to temperature and humidity
    unsigned int raw_temperature = (buffer[0] << 8) | buffer[1];
    unsigned int raw_humidity = (buffer[3] << 8) | buffer[4];

    *temperature = -45.0 + (175.0 * raw_temperature / 65535.0);
    *humidity = 100.0 * raw_humidity / 65535.0;

    return 0;
}

