        if (read_sensor(&temperature, &humidity) == 0) {
            char lcd_text[20];
            snprintf(lcd_text, sizeof(lcd_text), "Temp: %.2f C, Hum: %.2f %%", temperature, humidity);

            // Print data to LCD
