                fprintf(stderr, "Error printing to LCD\n");
            }

            // Log data to JSON file
            if (log_data(temperature, humidity) != 0) {
                fprintf(stderr, "Error logging data\n");
            }
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        gpioDelay(5000000); // 5 seconds delay
    }

    // Cleanup resources before exiting
    cleanup();

    return 0;
}

