#define HMC5883L_ADDR 0x1E // I2C address of the HMC5883L
#define HMC5883L_RA_X_MSB 0x03 // X MSB data register
#define HMC5883L_RA_CONFIG_A 0x00 // Configuration register A
#define HMC5883L_RA_MODE 0x02 // Mode register
#define LED_PIN 18 // GPIO pin connected to the LED

int main(int argc, char *argv[])
{
    // Initialize the library
    if (gpioInitialise() < 0)
    {
        printf("Failed to initialize the library\n");
        return 1;
    }

    // Open I2C bus
    int i2cHandle = i2cOpen(1, HMC5883L_ADDR, 0);
    if (i2cHandle < 0)
    {
        printf("Failed to open I2C bus\n");
        return 1;
    }

    // Set up the HMC5883L
    unsigned char configA[] = {0x70, 0xA0}; // 8-average, 15 Hz, normal measurement configuration
    if (i2cWriteDevice(i2cHandle, HMC5883L_RA_CONFIG_A, configA, 2) < 0)
    {
        printf("Failed to write to HMC5883L\n");
        return 1;
    }

    unsigned char mode[] = {0x00}; // Continuous measurement mode
    if (i2cWriteDevice(i2cHandle, HMC5883L_RA_MODE, mode, 1) < 0)
    {
        printf("Failed to write to HMC5883L\n");
        return 1;
    }

    // Set up the LED
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Main loop
    while (1)
    {
        // Read data from HMC5883L
        unsigned char buffer[6];
        if (i2cReadDevice(i2cHandle, HMC5883L_RA_X_MSB, buffer, 6) < 0)
        {
            printf("Failed to read from HMC5883L\n");
            return 1;
        }

        // Calculate heading
        int x = (buffer[0] << 8) | buffer[1];
        int y = (buffer[4] << 8) | buffer[5];
        float heading = (atan2(y, x) * 180.0) / PI;
        if (heading < 0)
            heading += 360;

        // Control the LED brightness based on the heading
        float dutyCycle = heading / 360;
        gpioPWM(LED_PIN, dutyCycle * 1000000);

        // Wait a bit
        sleep(1);
    }

    // Close I2C bus
    i2cClose(i2cHandle);

