        fprintf(stderr, "Error: Failed to set configuration register A.\n");
        return -1;
    }

    // Set configuration register B
    if (i2cWriteByteData(i2c_handle, HMC5883L_REG_CONFIG_B, 0xA0) != 0) {
        fprintf(stderr, "Error: Failed to set configuration register B.\n");
        return -1;
    }

    return 0;
}

