int read_magnetometer_data(int i2c_handle, int16_t *x, int16_t *y, int16_t *z) {
    char buf[6];

    if (i2cReadI2CBlockData(i2c_handle, HMC5883L_REG_DATA_X_MSB, buf, 6) != 6) {
        fprintf(stderr, "Error: Failed to read magnetometer data.\n");
        return -1;
    }

    *x = (int16_t)((buf[0] << 8) | buf[1]);
    *y = (int16_t)((buf[2] << 8) | buf[3]);
    *z = (int16_t)((buf[4] << 8) | buf[5]);

    return 0;
}

