double calculate_heading(int16_t x, int16_t y) {
    double heading = atan2(y, x) * 180.0 / M_PI;

    if (heading < 0) {
        heading += 360.0;
    }

    return heading;
}

// Function to map the heading to a PWM duty cycle (0-360 degrees to 0-100%)
int map_heading_to_pwm(double heading) {
    return (int)(heading * 3.6);
}

