    i2c_handle = i2cOpen(I2C_BUS, HMC5883L_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error: Failed to open I2C connection.\n");
        gpioTerminate();
        return 1;
    }

    // Initialize HMC5883L sensor
    if (initialize_hmc5883l(i2c_handle) != 0) {
        fprintf(stderr, "Error: HMC5883L initialization failed.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set GPIO pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Set PWM range
    gpioSetPWMrange(LED_PIN, 100);

    // Set PWM frequency
    gpioSetPWMfrequency(LED_PIN, 1000);

    // Set signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

