            printf("Heading: %.2f degrees, PWM: %d\n", heading, duty_cycle);
        } else {
            fprintf(stderr, "Error: Failed to read magnetometer data, retrying...\n");
        }

        // Sleep for 100 milliseconds
        usleep(100000);
    }

    return 0;
}

