                if (fp != NULL) {
                    fprintf(fp, "%s, %d, %d, %d\n", timestamp, proximity, als, uv_index);
                    fclose(fp);
                    printf("Data logged: %s, Proximity: %d, ALS: %d, UV Index: %d\n", timestamp, proximity, als, uv_index);

                    // Simulate window tint adjustment based on UV index
                    if (uv_index > 5) {
                        printf("Simulating window tint darkening due to high UV index.\n");
                    }
                } else {
                    fprintf(stderr, "Error opening sensor_log.txt for writing\n");
                }
            } else {
                fprintf(stderr, "Error reading sensor data, skipping logging.\n");
            }

            // Debounce: wait a short period before checking for motion again
            gpioDelay(200); // 200ms
        } else {
            // No motion detected, sleep for a short interval
            gpioDelay(100); // 100ms
        }
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

