#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/spi/spidev.h>
#include <unistd.h>

#define ARRAY_SIZE(a) (sizeof(a) / sizeof((a)[0]))

#define ADC_PATH "/dev/spidev0.0"
#define ADC_SPEED 5000000
#define ADC_MODE 0x08

static const char *device = ADC_PATH;

int readAdc(unsigned char adc_channel) {
    unsigned char buffer[3] = {1};
    char result[3] = {0, 0, 0};
    int fd;

    buffer[1] = adc_channel;

    if ((fd = open(device, O_RDWR)) < 0) {
        perror("Failed to open SPI device");
        return -1;
    }

    if (ioctl(fd, SPI_IOC_WR_MODE, &ADC_MODE) < 0) {
        perror("Failed to set SPI mode");
        return -1;
    }

    if (ioctl(fd, SPI_IOC_WR_MAX_SPEED_HZ, &ADC_SPEED) < 0) {
        perror("Failed to set SPI speed");
        return -1;
    }

    if (write(fd, buffer, ARRAY_SIZE(buffer)) != ARRAY_SIZE(buffer)) {
        perror("Failed to write to SPI device");
        return -1;
    }

    if (read(fd, result, ARRAY_SIZE(result)) != ARRAY_SIZE(result)) {
        perror("Failed to read from SPI device");
        return -1;
    }

    close(fd);

    return ((result[1] << 8) & 0x300) | (result[2] & 0xFF);
}

int main(int argc, char **argv) {
    FILE *file;
    file = fopen("adc_data.csv", "w");
    if (file == NULL) {
        printf("Failed to open file\n");
        return 1;
    }
    while (1) {
        int adc_value = readAdc(0);
        fprintf(file, "%d\n", adc_value);
        fflush(file);
        sleep(1);
    }
    fclose(file);
    return 0;
}

