    if (gpioInitialise() < 0)
    {
        syslog(LOG_ERR, "Cannot initialize GPIO library");
        return 1;
    }
    syslog(LOG_INFO, "GPIO library initialized");

    gpioSetMode(PIR_PIN, PI_INPUT);
