#define BUZZER_GPIO 18
#define BUZZER_DURATION_MS 500
#define SERVER_IP "127.0.0.1" // Replace with your server IP
#define SERVER_PORT 12345

volatile sig_atomic_t program_running = 1;

void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off
    gpioTerminate();
    exit(0);
}

void motion_detected_callback(int gpio, int level, uint32_t tick) {
    if (level == 1) { // Rising edge detected (motion detected)
        time_t now = time(NULL);
        struct tm *tstruct;
        char buf[80];
        tstruct = localtime(&now);
        strftime(buf, sizeof(buf), "%Y-%m-%d %H:%M:%S", tstruct);

        printf("%s: Motion detected on GPIO %d\n", buf, PIR_GPIO);

        // Log event to syslog
        FILE *fp = fopen("/var/log/motion_events.log", "a");
        if (fp != NULL) {
            fprintf(fp, "%s: Motion detected on GPIO %d\n", buf, PIR_GPIO);
            fclose(fp);
        } else {
            perror("Error opening log file");
        }

        // Trigger buzzer
        gpioWrite(BUZZER_GPIO, 1);
        gpioDelay(BUZZER_DURATION_MS * 1000); // Delay for 500ms
        gpioWrite(BUZZER_GPIO, 0);

        // Send event to central server
        int sockfd;
        struct sockaddr_in servaddr;

        // Creating socket file descriptor
        if ((sockfd = socket(AF_INET, SOCK_DGRAM, 0)) < 0) {
            perror("socket creation failed");
            return;
        }

        memset(&servaddr, 0, sizeof(servaddr));
        servaddr.sin_family = AF_INET;
        servaddr.sin_port = htons(SERVER_PORT);

        // Convert IPv4 and IPv6 addresses from text to binary form
        if (inet_pton(AF_INET, SERVER_IP, &servaddr.sin_addr) <= 0) {
            perror("Invalid address/ Address not supported");
            close(sockfd);
            return;
        }

        char message[256];
        snprintf(message, sizeof(message), "%s: Motion detected on GPIO %d", buf, PIR_GPIO);

        sendto(sockfd, (const char *)message, strlen(message), 0, (const struct sockaddr *)&servaddr, sizeof(servaddr));
        close(sockfd);
    }
}

