    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO 17 as input
    if (gpioSetMode(PIR_GPIO, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as input\n", PIR_GPIO);
        gpioTerminate();
        return 1;
    }

    // Set GPIO 18 as output
    if (gpioSetMode(BUZZER_GPIO, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d as output\n", BUZZER_GPIO);
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Register callback function for motion detection
    if (gpioSetAlertFunc(PIR_GPIO, motion_detected_callback) != 0) {
        fprintf(stderr, "Failed to set alert function for GPIO %d\n", PIR_GPIO);
        gpioTerminate();
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    while (program_running) {
        gpioDelay(100 * 1000); // Check every 100ms
    }

    return 0;
}

