#include <errno.h>
#include <unistd.h>
#include <signal.h>

// Define GPIO pins
#define PIR_PIN 17
#define BUZZER_PIN 18

// Define buzzer activation duration in milliseconds
#define BUZZER_DURATION 2000

// Global flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize_gpio();
int read_pir_sensor(int pin);
void activate_buzzer(int pin, int duration);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, exiting gracefully...\n", signal);
    program_running = 0;
}

// Function to initialize wiringPi and GPIO pins
int initialize_gpio() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    pinMode(PIR_PIN, INPUT);
    pinMode(BUZZER_PIN, OUTPUT);

    return 0;
}

// Function to read the PIR sensor value
int read_pir_sensor(int pin) {
    return digitalRead(pin);
}

// Function to activate the buzzer for a specified duration
void activate_buzzer(int pin, int duration) {
    digitalWrite(pin, HIGH); // Turn on the buzzer
    delay(duration);          // Wait for the specified duration
    digitalWrite(pin, LOW);  // Turn off the buzzer
}

int main() {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() == -1) {
        return 1;
    }

    fprintf(stderr, "PIR sensor monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int pir_value = read_pir_sensor(PIR_PIN);

        if (pir_value == 1) {
            fprintf(stderr, "Motion detected!\n");
            activate_buzzer(BUZZER_PIN, BUZZER_DURATION);
            delay(500); // Debounce delay
        }

        delay(100); // Small delay to reduce CPU usage
    }

    // Clean up GPIO pins before exiting
    digitalWrite(BUZZER_PIN, LOW); // Ensure buzzer is off
    pinMode(PIR_PIN, INPUT);       // Set PIR_PIN as input
    pinMode(BUZZER_PIN, INPUT);    // Set BUZZER_PIN as input

    fprintf(stderr, "Exiting.\n");

    return 0;
}

